#include<bits/stdc++.h>
using namespace std;

// This function prints the start and end times, along with the names of the people who are available during that timeslot.
void printValues(int start, int end, vector<string>& names) {
  if (start != end) {
    cout << start << " " << end << " ";
    for (auto name : names) cout << name << " ";
    cout << "\n";
  }
}

// This function takes an unordered map of strings to pairs of integers as input. The strings represent the names of people, and the pairs of integers represent the start and end times of their availability. The function prints a list of all the timeslots during which at least one person is available.
void allAvailable(unordered_map<string, pair<int, int>>& arr) {

  // Create a vector of pairs of integers, where the first integer is the start time and the second integer is the type of event (start or end).
  vector<pair<int, pair<string, string>>> res;
  for (auto x : arr) {
    string name = x.first;
    int start = x.second.first, end = x.second.second;
    res.push_back({start, {name, "start"}});
    res.push_back({end, {name, "end"}});
  }

  // Sort the vector by start time.
  sort(res.begin(), res.end());

  // Initialize the start and end times, and the vector of names.
  int start = res[0].first, end = -1;
  vector<string> names;
  names.push_back(res[0].second.first);

  // Iterate through the vector.
  for (int i = 1; i < res.size(); i++) {

    // Get the current event.
    auto x = res[i];
    int val = x.first;
    string name = x.second.first;
    string startEnd = x.second.second;

    // Update the end time.
    end = val;

    // If the current event is a start event, print the current timeslot and add the name to the vector of names.
    if (startEnd == "start") {
      printValues(start, end, names);
      names.push_back(name);
    }

    // If the current event is an end event, print the current timeslot and remove the name from the vector of names.
    else {
      printValues(start, end, names);
      auto it = find(names.begin(), names.end(), name);
      names.erase(it);
    }

    // Update the start time.
    start = val;
  }
}

int main() {

  // Create an unordered map of strings to pairs of integers.
  unordered_map<string, pair<int, int>> arr;
  arr["Amanda"] = {10, 100};
  arr["Alex"] = {30, 40};
  arr["Frank"] = {50, 120};
  arr["Henry"] = {100, 110};
  arr["Susan"] = {120, 140};
  arr["Thomas"] = {80, 110};
  arr["George"] = {70, 90};

  // Call the allAvailable function.
  allAvailable(arr);

  // Return 0.
  return 0;
}
